insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('endpoint', 'Endpoint', '', '', ARRAY['endpoint','api endpoint','serving endpoint']::text[], 'Core', 'The URL or address where you send a request and the model sends back its answer.', 'Like a ticket window at the post office — you hand in your request and wait for the response.', 'You call `https://api.example.com/v1/completions` with your prompt, and the endpoint replies with generated text.', '[]'::jsonb, 'An endpoint is a running service listening on a network address. It receives JSON payloads, passes them through the model, and streams or returns the output. Uptime, latency, and throughput all depend on how the endpoint is built and where it runs.', 'Endpoints are the interface between your app and the model — their reliability and speed shape user experience.', 'An HTTP(S) endpoint backed by a running inference server that decodes requests, invokes the model, and serializes responses.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('ratelimit', 'Rate limit', '', '', ARRAY['rate limit','throttle']::text[], 'Core', 'A cap on how many requests your endpoint will accept in a given time window.', 'A security guard at a concert who only lets in 100 people per minute to avoid crushing.', 'Your API might allow 100 requests per second; after that, new requests get a 429 error and have to wait or retry.', '[{"text":"How long responses take when queued."}]'::jsonb, 'Rate limits protect the backend from overload and ensure fair use across clients. They''re enforced at the gateway or application level and can be per-user, per-IP, or global. When hit, clients should backoff exponentially — hammering harder makes it worse.', 'Rate limits protect your costs and infrastructure, but too strict and they frustrate power users.', 'A sliding window or token-bucket counter that rejects requests once a threshold is crossed.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('costpertoken', 'Cost per token', '', '', ARRAY['cost per token','token cost','pricing']::text[], 'Core', 'The price you pay for each token processed — input and output are usually charged separately.', 'Like paying by the word instead of by the page.', 'A model might cost $0.01 per 1K input tokens and $0.03 per 1K output tokens; a 1000-token response costs $0.03.', '[]'::jsonb, 'Different models have different per-token prices. Larger models, newer models, and models with longer context windows cost more per token. Input and output are usually split because output tokens require more compute. Your bill is input_tokens × input_price + output_tokens × output_price.', 'Per-token pricing is the main driver of LLM inference costs — choosing the right model size and prompt compression matters hugely.', 'Price is set by the provider; your job is to count input and output tokens accurately and track spending.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('caching', 'Caching', '', '', ARRAY['caching','cache']::text[], 'Core', 'Storing computed results so you don''t have to recompute them when the same request comes in again.', 'Writing down yesterday''s math homework so you don''t have to solve it again today.', 'If 10 users all ask the same question, the first call generates the answer; the next 9 see the cached result instantly.', '[]'::jsonb, 'Caching happens at multiple levels: KV caching during a single forward pass (storing attention keys and values), prompt caching (reusing embeddings of long context), and application-level caching (storing full responses). Cache misses waste compute; cache hits save both latency and money.', 'Caching is the fastest, cheapest way to speed up responses — if you can predict repeated patterns.', 'Implement cache-key semantics carefully — wrong keys cause stale responses; too many cache layers and debugging becomes hell.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('coldstart', 'Cold start', '', '', ARRAY['cold start','startup time','initialization']::text[], 'Core', 'The delay when a service boots up and hasn''t finished loading the model into memory yet.', 'The time it takes to warm up a car engine on a freezing morning.', 'A Lambda function gets invoked for the first time and spends 5 seconds loading the model weights before it can process the first request.', '[]'::jsonb, 'Cold starts happen when no instance is running and a new one has to spin up, load the model from disk or network, and prepare it for inference. For large models, loading itself can take seconds. Keeping warm instances running costs money; letting them sleep saves money but introduces latency.', 'Cold starts hurt user experience on low-traffic services — trade-off between cost and responsiveness.', 'Minimize loading time: quantize models, use fast storage (NVMe vs network), parallelize loading, or keep instances warm.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('autoscaling', 'Autoscaling', '', '', ARRAY['autoscaling','auto scaling','scale automatically']::text[], 'Core', 'Automatically spinning up more instances when traffic spikes and tearing them down when it drops.', 'A restaurant that hires temp workers when the lunch rush hits and sends them home at 2pm.', 'Your inference service normally runs 2 replicas; at 9am traffic jumps and the system automatically brings 5 more online; by noon it scales back to 2.', '[]'::jsonb, 'Autoscaling uses metrics like CPU, memory, or request queue depth to decide when to add or remove instances. Scaling *up* takes time (cold start overhead); scaling *down* means losing capacity mid-spike if you''re not careful. Metrics lag behind actual load, so good autoscaling tuning matters.', 'Autoscaling lets you handle spikes without overpaying for idle capacity.', 'Set scaling thresholds carefully — too aggressive and you''ll waste money on temporary instances; too conservative and you''ll serve slow responses during spikes.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('mlops', 'MLOps', '', '', ARRAY['mlops','machine learning operations','ml operations']::text[], 'Rising', 'The operational practices for training, testing, deploying, and monitoring machine learning models in production.', 'DevOps for ML — managing the full lifecycle instead of just shipping code once.', 'An MLOps team monitors model drift, retrains when accuracy drops, version-controls datasets, and automates canary deployments.', '[]'::jsonb, 'MLOps covers data pipeline management, model versioning, experiment tracking, automated retraining, A/B testing, and monitoring for data drift or distribution shift. Unlike traditional software, ML systems can degrade silently if the world changes but your model doesn''t.', 'MLOps is the unglamorous work that keeps models from rotting in production.', 'Build reproducible training pipelines, version everything (code, data, models), and monitor for covariate shift.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('llmops', 'LLMOps', '', '', ARRAY['llmops','llm operations','large language model ops']::text[], 'Rising', 'The operational practices specific to deploying and managing large language models — prompt versioning, output validation, cost tracking.', 'MLOps''s younger, more chaotic sibling focused on inference rather than training.', 'Versioning prompts alongside model versions, A/B testing different system prompts, monitoring token costs and latency per model.', '[]'::jsonb, 'LLMOps is a newer discipline because LLM inference is different from training: you''re not retraining constantly, you''re prompt-engineering and model-picking. Tracking what prompt produced what output, versioning system prompts like code, and catching quality regressions early are the key jobs.', 'LLMOps keeps LLM applications reliable and cost-effective as you iterate on prompts.', 'Treat prompts as versioned code; log outputs for offline evaluation; track token usage per endpoint.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('observability', 'Observability', '', '', ARRAY['observability','monitoring','logging','traces']::text[], 'Core', 'Collecting logs, metrics, and traces so you can understand what your system is doing right now and why it failed.', 'Installing cameras and a dashboard in your factory so you can see what''s happening on the assembly line.', 'When a request is slow, you can see traces showing where time was spent: 2s in tokenization, 3s in model forward pass, 1s in response serialization.', '[]'::jsonb, 'Observability is three pillars: logs (discrete events), metrics (aggregated numbers over time), and traces (request journeys through the system). You need all three — logs tell you *what* happened, metrics show *patterns*, traces show *cause*. Good observability tools let you correlate them.', 'Observability is how you know if users are happy and where money is being wasted.', 'Instrument all critical paths; use structured logging; emit traces; correlate with spans.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('modelserving', 'Model serving', '', '', ARRAY['model serving','serving','inference serving']::text[], 'Core', 'Running a model as a live service that accepts requests and returns predictions, rather than training or batch processing.', 'Running a restaurant open for lunch instead of just cooking at home for family.', 'Serving a model via an API that clients POST prompts to and get back completions.', '[{"text":"The URL where you send requests.","id":"endpoint"}]'::jsonb, 'Model serving requires orchestrating compute, managing the model''s memory footprint, handling concurrent requests, and keeping latency low. You need to pick hardware (GPU, CPU, TPU), choose inference software (vLLM, TensorRT, etc.), and set up monitoring and autoscaling.', 'Model serving is where inference goes live and starts costing money proportional to usage.', 'Optimize for throughput and latency; batch where you can; manage memory carefully.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('vllm', 'vLLM', '', '', ARRAY['vllm','v-llm','vllm inference engine']::text[], 'Rising', 'An inference engine optimized for fast LLM serving — uses PagedAttention to avoid wasteful memory fragmentation.', 'A smart warehouse manager who packs boxes efficiently so none of the shelf space is wasted.', 'vLLM can serve more concurrent requests per GPU than vanilla PyTorch because it doesn''t allocate a full context window per request upfront.', '[]'::jsonb, 'vLLM''s key trick is PagedAttention — KV cache (attention keys and values) are paged into blocks dynamically rather than pre-allocated in full. This lets you fit more requests on the same GPU memory. It also supports continuous batching (processing requests at different paces) and speculative decoding.', 'vLLM can cut your inference costs by 3-4x by letting you pack more requests per GPU.', 'vLLM abstracts away low-level CUDA — use its Python API or OpenAI-compatible REST endpoint.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('tensorrt', 'TensorRT', '', '', ARRAY['tensorrt','tensor-rt','nvidia tensorrt']::text[], 'Rising', 'An NVIDIA compiler that optimizes neural networks for fast inference on NVIDIA GPUs.', 'A mechanic who fine-tunes your car engine for a specific track.', 'Compiling a PyTorch model with TensorRT can 2-4x its inference speed with minimal accuracy loss.', '[]'::jsonb, 'TensorRT fuses operations (e.g., combining Conv+ReLU into one kernel), converts to lower precision (FP16, INT8), optimizes memory layout, and generates CUDA kernels. It''s specific to NVIDIA hardware but offers the fastest speeds on that platform.', 'TensorRT is the go-to for squeezing max throughput from NVIDIA GPUs.', 'TensorRT has a learning curve and is NVIDIA-only; good if you''re committed to that hardware.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('onnx', 'ONNX', '', '', ARRAY['onnx','open neural network exchange']::text[], 'Rising', 'An open standard format for neural networks so you can train in one framework and run inference in another.', 'Like PDF for neural networks — save once, read anywhere.', 'Train a model in PyTorch, export it as ONNX, and run it in C++ or JavaScript without rewriting.', '[]'::jsonb, 'ONNX is a graph format that represents computation as an acyclic graph of operations. Runtimes like ONNX Runtime, TensorRT, and others can optimize and run it. It doesn''t lock you to one framework, though exporting and importing always involves some friction.', 'ONNX lets you decouple model development from deployment technology choices.', 'ONNX is solid for deploying PyTorch and TensorFlow models; gaps still exist for newest ops.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('modelquantization', 'Model quantization', '', '', ARRAY['quantization','model quantization','quantize']::text[], 'Rising', 'Converting model weights from high-precision floats (FP32) to lower precision (FP16, INT8) to save memory and speed up inference.', 'Compressing a FLAC audio file to MP3 — loses some precision but much smaller.', 'An 8GB model in FP32 becomes 2GB in INT8, runs 2-4x faster, and stays accurate enough for most uses.', '[]'::jsonb, 'Lower precision means fewer bits per weight. FP16 uses 16 bits per float; INT8 uses 8 bits and requires careful scaling. Post-training quantization (apply it after training) is easy but loses more accuracy; quantization-aware training (teach the model during training that it''ll be quantized) is better but costs training time.', 'Quantization can cut costs 3-4x by reducing memory and compute without huge accuracy loss.', 'Use libraries like GPTQ or bitsandbytes; measure accuracy on your actual use cases.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('activationquantization', 'Activation quantization', '', '', ARRAY['activation quantization','act quantization','kv cache quantization']::text[], 'Rising', 'Quantizing the intermediate values (activations) inside a forward pass, not just the weights.', 'Like cleaning up not just your filing cabinet but also the sticky notes on your desk.', 'Quantizing both weights and KV cache in an LLM inference, saving memory and compute.', '[{"text":"Converting weights to lower precision.","id":"modelquantization"}]'::jsonb, 'Weights are static and you can calibrate quantization offline. Activations vary per input, so you need dynamic quantization or per-batch calibration. KV cache quantization (quantizing attention keys and values) is especially valuable for long-context inference.', 'Activation quantization can push down memory even further when weight quantization alone isn''t enough.', 'Activation quantization is trickier than weight quantization; use mature libraries or expect calibration headaches.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('gptq', 'GPTQ', '', '', ARRAY['gptq','gpt quantization']::text[], 'Rising', 'A quantization method that uses the Hessian to intelligently decide which weights to quantize less, so you get good accuracy at low bit-widths.', 'A smart editor who cuts the least important words to make a story fit in fewer pages.', 'Using GPTQ you can quantize GPT models to 3 bits with minimal accuracy loss, or 4 bits with nearly no loss.', '[]'::jsonb, 'GPTQ computes the Hessian (second-order information) about which weights matter most, then uses that to set per-weight quantization scales. It''s slower to apply than simple post-training quantization, but the accuracy payoff is huge. Ollama and text-generation-webui popularized pre-quantized GPTQ models.', 'GPTQ is the standard for distributing small, fast, accurate open-source models.', 'GPTQ models are fast and efficient; libraries like GPTQ-for-LLaMA or Marlin make them easy to use.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('awq', 'AWQ', '', '', ARRAY['awq','activation-weighted quantization']::text[], 'Rising', 'A newer quantization method that quantizes less aggressively on activations that matter most, beating GPTQ on speed.', 'Like GPTQ''s smarter cousin — spends effort protecting the parts that do the most work.', 'AWQ-quantized models run faster than GPTQ at the same quantization bit-width because the runtime is more efficient.', '[]'::jsonb, 'AWQ observes that some activations contribute more to the output than others (high variance). It protects those by scaling them up before quantization, then scales back down. It''s also designed to be faster to run (not just faster to quantize). AWQ trades off against GPTQ: sometimes GPTQ is more accurate, sometimes AWQ is faster.', 'AWQ is gaining adoption for inference optimization — speeds up inference compared to GPTQ.', 'AWQ runtimes are optimized for speed; check if your inference engine supports it.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('gguf', 'GGUF', '', '', ARRAY['gguf','ggml file format','llama.cpp format']::text[], 'Rising', 'A file format for storing quantized models that''s lightweight and efficient for CPU and small-device inference.', 'A portable, self-contained suitcase for neural networks.', 'Run a 7B-parameter model on your laptop by loading a GGUF file into llama.cpp.', '[{"text":"Popular inference engine that uses GGUF.","id":"llamacpp"}]'::jsonb, 'GGUF stores quantized weights in a streamlined binary format with metadata. It''s designed to be fast to load and require minimal memory. Llama.cpp and Ollama popularized it by making quantized open-source models accessible on regular hardware.', 'GGUF is how millions of people run LLMs on laptops and phones — it democratizes access.', 'GGUF is the standard for CPU-friendly inference; llama.cpp, Ollama, and many others support it.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('llamacpp', 'llama.cpp', '', '', ARRAY['llama.cpp','llamacpp','llama-cpp']::text[], 'Rising', 'A lightweight C++ inference engine optimized for running GGUF models on consumer hardware (CPUs and weak GPUs).', 'The Honda Civic of LLM inference engines — small, reliable, and works on anything.', 'Run a 7B-parameter model on a MacBook or Linux laptop using llama.cpp and get 10+ tokens per second.', '[{"text":"GGUF format that llama.cpp uses.","id":"gguf"}]'::jsonb, 'Llama.cpp is pure C++ with SIMD optimizations (AVX2, NEON) for CPU inference. It''s also got basic GPU support (CUDA, Metal, Vulkan) and can run on almost any device from phones to servers. The main trade-off is latency — it''s slower than vLLM or TensorRT but doesn''t need GPUs.', 'Llama.cpp is the gateway to running open LLMs locally — privacy and cost matter.', 'Llama.cpp is easy to deploy and has solid community momentum; it''s your go-to for CPU inference.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('batchinference', 'Batch inference', '', '', ARRAY['batch inference','batching','inference batching']::text[], 'Core', 'Processing multiple requests together in one forward pass instead of one at a time, which is much faster per request.', 'Sending 10 letters in one mail batch instead of 10 separate trips to the post office.', 'Instead of running the model 100 times on 100 individual prompts, you group them into batches of 32 and run 4 batches — same total compute but much faster wall-clock time.', '[]'::jsonb, 'Batching amortizes the overhead of a forward pass (loading model to GPU, cache management) across multiple requests. Batch size is limited by memory. Small batches waste compute potential; large batches need more memory. Good inference systems balance request throughput with latency via continuous batching (requests arrive and leave asynchronously).', 'Batching is the #1 lever for throughput — more requests per second with the same hardware.', 'Implement continuous batching so requests don''t block; use dynamic batch sizes.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('streaming', 'Streaming', '', '', ARRAY['streaming','streaming response']::text[], 'Core', 'Sending tokens back to the client as soon as they''re generated instead of waiting for the full response.', 'Watching a video as it downloads instead of waiting for the whole file.', 'A chat interface shows words appearing one by one as the model generates them, instead of a long pause then all text at once.', '[{"text":"Protocol for streaming responses.","id":"serversent events"}]'::jsonb, 'Streaming trades off latency perception for architectural complexity. The client gets feedback immediately (feels fast), but you need to maintain the connection and send partial data. Server-Sent Events (SSE) or WebSockets are typical. Generators/iterators on the server simplify implementation.', 'Streaming makes LLMs feel snappy — users see progress instead of staring at a spinner.', 'Streaming requires careful connection management and error handling; SSE is simpler than WebSockets.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('serversent events', 'Server-sent events', '', '', ARRAY['server-sent events','sse','event stream']::text[], 'Core', 'A simple protocol where the server pushes updates to the client over a long-lived HTTP connection.', 'Like a news ticker — you tune in and the server pushes updates; you don''t ask for each one.', 'A chat API uses SSE so the model''s response tokens arrive one-by-one as soon as they''re ready.', '[{"text":"Sending responses as they generate.","id":"streaming"}]'::jsonb, 'SSE is HTTP-based (so it works through proxies and firewalls), uses a simple text format (each line is a JSON event), and handles reconnection automatically. It''s one-way (server to client), so it''s simpler than WebSockets but can''t do bidirectional streaming.', 'SSE is the standard for streaming LLM responses — easy to use from browsers and backends.', 'SSE is built into browsers; no library needed. Standard format: `data: {...}\n\n`.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('loadbalancing', 'Load balancing', '', '', ARRAY['load balancing','load balancer','distribute requests']::text[], 'Core', 'Distributing incoming requests across multiple servers or GPUs so no single one gets overloaded.', 'A traffic cop directing cars to different lanes so no lane jams up.', '10 inference servers sit behind a load balancer; each new request goes to the least-busy server.', '[]'::jsonb, 'Load balancers can use different strategies: round-robin (simple but dumb), least-connections (fewer requests), least-loaded (measured CPU/memory), or health-check-aware (skip dead servers). At scale, you need geographically distributed load balancing too.', 'Load balancing is how you go from one server to many without users noticing.', 'Use a proven balancer (Nginx, HAProxy, cloud load balancers) and monitor health carefully.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('memorybandwidth', 'Memory bandwidth', '', '', ARRAY['memory bandwidth','bandwidth']::text[], 'Core', 'How fast data can be moved from memory to the compute unit — often the bottleneck in LLM inference.', 'The width of a highway — a wider highway lets more cars through per second.', 'A GPU with 2 TB/s bandwidth can load more weights per cycle than one with 500 GB/s.', '[]'::jsonb, 'Modern GPUs have massive compute (trillions of FLOPs) but limited bandwidth (hundreds of GB/s). For LLMs, loading weights is often slower than the math itself — you''re memory-bound, not compute-bound. Quantization, batching, and optimized kernels all help because they either use less memory or reuse loaded data more.', 'Memory bandwidth is why inference is cheaper than training — it''s the limiting resource, not raw compute.', 'Measure compute-bound vs memory-bound; optimize accordingly (fused kernels, better batch sizes).', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('computebound', 'Compute bound', '', '', ARRAY['compute bound','compute-bound','cpu bound']::text[], 'Core', 'A workload is compute-bound when the processor is the limiting factor — you could feed it data faster and it''d keep up.', 'A fast eater at an all-you-can-eat buffet — never waiting for food.', 'Matrix multiplication on large matrices is usually compute-bound; the CPU/GPU does useful work the whole time.', '[{"text":"When memory is the bottleneck instead.","id":"memorybound"}]'::jsonb, 'Compute-bound is the happy case — your hardware is busy. Memory-bound is the sad case — your hardware is waiting. You''re compute-bound if adding more memory bandwidth doesn''t help. Identifying which you are is step one of optimization.', 'Compute-bound workloads scale well; memory-bound ones need different strategies (quantization, smaller batches).', 'Profile with tools like nsys or roofline analysis to confirm you''re compute-bound before optimizing compute.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('memorybound', 'Memory bound', '', '', ARRAY['memory bound','memory-bound','bandwidth limited']::text[], 'Core', 'A workload is memory-bound when moving data is slower than processing it — the hardware spends time waiting for data.', 'A fast reader at a library with only one slow printer — printing takes forever even though the reader is quick.', 'LLM inference is often memory-bound — loading model weights from memory is slower than the forward pass math.', '[{"text":"When compute is the bottleneck instead.","id":"computebound"},{"text":"The limiting data throughput.","id":"memorybandwidth"}]'::jsonb, 'Memory-bound is common in LLMs because the arithmetic intensity (math per byte loaded) is low — you load huge weight matrices but do relatively little math per weight in inference. Batching helps (you reuse weights across requests), as does quantization (fewer bytes to load) or kernel fusion (keep data in cache between operations).', 'Memory-bound inference means cost-per-token is limited by bandwidth, not chip power.', 'To optimize memory-bound workloads: reduce data size (quantization), fuse kernels, or increase batch size.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('flops', 'FLOPS', '', '', ARRAY['flops','floating point operations per second','gflops','tflops']::text[], 'Core', 'Floating-point operations per second — a measure of raw compute power.', 'Horsepower for chips — higher number sounds better, but doesn''t always translate to real-world speed.', 'A modern GPU might do 10 trillion FLOPS (10 TFLOPS); a model taking 100 trillion operations would take ~10 seconds.', '[]'::jsonb, 'FLOPS is a useful yardstick but can be misleading. Peak FLOPS (theoretical max) is rarely reached. Actual throughput depends on memory bandwidth, kernel efficiency, and problem size. It''s also usually measured as FP32; FP16 or INT8 can be faster or slower depending on the hardware.', 'FLOPS is one number but not the only one that matters — latency and throughput matter more.', 'Use FLOPS for napkin math, but profile your actual code to see real throughput.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('utilization', 'Utilization', '', '', ARRAY['utilization','gpu utilization','resource utilization']::text[], 'Core', 'The percentage of the GPU/CPU''s total capacity that''s actually being used — idle hardware is wasted money.', 'How full a delivery truck is when it leaves — 100% utilization means no empty space.', 'A GPU running inference at 60% utilization means 40% of its compute power is sitting idle.', '[]'::jsonb, 'High utilization is the goal — it means you''re squeezing value from your hardware. For inference, this usually means batching (more requests) or larger models. For training, it often means larger batch sizes. Low utilization usually signals memory pressure (can''t fit bigger batches) or architectural bottlenecks.', 'High utilization = cheaper cost-per-inference; low utilization = overpaying for idle hardware.', 'Monitor utilization and profile bottlenecks; if it''s memory, try quantization; if it''s waiting, try batching.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('concurrency', 'Concurrency', '', '', ARRAY['concurrency','concurrent requests','parallel requests']::text[], 'Core', 'How many requests are being processed at the same time — high concurrency means more throughput on the same hardware.', 'A cashier with 5 checkout lanes running simultaneously is more concurrent than 1 lane.', 'A server that handles 100 concurrent requests will serve more total requests than one that only handles 10 at a time.', '[]'::jsonb, 'Concurrency is bounded by memory and compute. Each concurrent request needs some memory (KV cache, input/output buffers). Continuous batching lets you mix requests at different completion stages (one nearly done, one just started) for better GPU utilization.', 'High concurrency on the same hardware means more users served per dollar.', 'Use continuous batching and careful memory management to support high concurrency.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('requestqueue', 'Request queue', '', '', ARRAY['request queue','queue','request backlog']::text[], 'Core', 'A buffer of pending requests waiting to be processed — long queues mean slow response times.', 'A line at the grocery store — the longer the line, the longer you wait.', 'Under load, 500 requests per second arrive but the server can only handle 400/s, so the queue grows and responses get slower.', '[]'::jsonb, 'Queue depth is a key metric. If it''s growing, the system is overloaded. If it''s consistently long, you need to scale. Queue depth also affects latency perception — users see tail latency spike when the queue builds up.', 'Queue depth is a leading indicator of whether you need to scale or adjust pricing.', 'Monitor queue depth; when it grows, scale immediately (or shed load via rate limiting).', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('tokenstreaming', 'Token streaming', '', '', ARRAY['token-streaming']::text[], 'Core', 'Returning generated tokens one-by-one as they''re produced instead of waiting for the entire response.', 'Getting subtitles in real-time during a movie instead of waiting until it''s over.', 'In a chat app, you see words appear as the model generates them rather than a 5-second pause then all text at once.', '[{"text":"Sending responses as they generate.","id":"streaming"}]'::jsonb, 'Token streaming is both a user-experience win (feels responsive) and an implementation challenge (need persistent connections). The server keeps the connection open and pushes tokens via SSE, WebSocket, or gRPC streaming. Clients need to handle backpressure if they can''t consume tokens fast enough.', 'Token streaming is the ''secret sauce'' that makes LLM chats feel snappy.', 'Use SSE or WebSockets; make sure your inference engine can stream tokens incrementally.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('taillatency', 'Tail latency', '', '', ARRAY['tail latency','worst-case latency']::text[], 'Core', 'The latency of the slowest requests (e.g., p99 or p95) — much more important to user experience than average latency.', 'One slow checkout line ruins the shopping trip even if 99 others are fast.', 'Average latency is 50ms, but p99 is 500ms — some users wait 10x longer, which feels broken.', '[{"text":"The 99th percentile metric.","id":"p99latency"}]'::jsonb, 'Average latency can be misleading. If 99% of requests are 50ms and 1% are 500ms, the average looks good but users in that tail suffer. Tail latency is caused by GC pauses, OS scheduling, cache misses, or congestion. Reducing tail latency often means: better hardware isolation, fast autoscaling, or shedding load.', 'P99 latency determines user experience — focus on it, not average.', 'Profile and eliminate sources of variance; prioritize speed over average efficiency.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('p99latency', 'P99 latency', '', '', ARRAY['p99','99th percentile']::text[], 'Core', 'The latency at the 99th percentile — 99% of requests are faster, 1% are slower.', 'If you survey 100 people, p99 is the slowest person''s time.', 'P99 latency = 200ms means 99 out of 100 requests complete in 200ms or less; 1 in 100 takes longer.', '[{"text":"The slowest requests.","id":"taillatency"}]'::jsonb, 'P99 is a standard SLA target in production. It''s one number that sums up the tail. Other percentiles: p95 (95th), p50 (median), p999 (99.9th). P99 is strict enough to catch problems but not so strict (like p999) that outliers dominate.', 'P99 latency is your SLA promise to customers — publish it and defend it.', 'Set P99 budgets and profile to find bottlenecks; reduce variance more than average.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('sla', 'SLA', '', '', ARRAY['sla','service level agreement']::text[], 'Core', 'A commitment to customers about uptime and performance — if you miss it, they get refunds or credits.', 'A warranty on your service — ''we promise 99.9% uptime or your money back.''', 'An SLA might be ''99.5% uptime and p99 latency < 500ms'' — you monitor and refund if you miss either.', '[]'::jsonb, 'SLAs are business contracts backed by engineering discipline. They drive infrastructure decisions (redundancy, monitoring, autoscaling). Exceeding SLAs is good; violating them costs money. SLA != SLO (objective) — SLA is the promise, SLO is what you aim for internally (usually higher).', 'SLAs are your customers'' recourse; enforce them internally with even stricter SLOs.', 'Build infrastructure to meet SLAs reliably; monitor like your paycheck depends on it.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('uptime', 'Uptime', '', '', ARRAY['uptime']::text[], 'Core', 'The percentage of time your service is available and working — 99.9% uptime means ~8 hours of downtime per year.', 'A diner open 365 days a year except for a few brief closures for maintenance.', '99.9% uptime = 99.9% of time, 0.1% downtime = 43 minutes downtime per month.', '[]'::jsonb, 'Uptime is usually measured per month or year. Higher targets (99.99% = 4 minutes/month, 99.999% = 26 seconds/month) require redundancy, fast failover, and careful deployment. Each 9 costs exponentially more. Most AI services target 99.9-99.95%.', 'Higher uptime targets justify higher prices — enterprise customers pay for it.', 'Redundancy, automated recovery, and safe deploys are how you achieve high uptime.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('failover', 'Failover', '', '', ARRAY['failover','fail over','automatic failover']::text[], 'Core', 'Automatically switching to a backup system when the primary one fails — ideally without users noticing.', 'An elevator with a backup power system that kicks in if the main power cuts.', 'A request gets routed to server A; server A crashes; the load balancer automatically sends it to server B.', '[]'::jsonb, 'Failover can be automatic (health checks detect failure and redirect) or manual. Automatic failover is complex — you need to detect failure quickly (false positives trigger unnecessary switches), coordinate state, and maintain data consistency. DNS failover is slow; load-balancer-based failover is fast.', 'Good failover is invisible to users and crucial for uptime guarantees.', 'Implement health checks carefully; test failover scenarios; use local retry logic.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('redundancy', 'Redundancy', '', '', ARRAY['redundancy','backup','redundant system']::text[], 'Core', 'Having backups of critical systems so if one fails, another is ready to take over.', 'Having two parachutes instead of one.', 'Three inference servers instead of one — any two going down still leaves one answering requests.', '[]'::jsonb, 'Redundancy costs money but buys uptime. For stateless services (like inference), it''s simple — just run more copies. For stateful services, you need distributed consensus and careful coordination. Redundancy has to cover everything: servers, storage, network.', 'Redundancy is the most straightforward way to improve uptime and user trust.', 'Redundancy is cheap compared to downtime; over-invest here.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('horizontalscaling', 'Horizontal scaling', '', '', ARRAY['horizontal scaling','scale out','adding instances']::text[], 'Core', 'Adding more machines to spread the load instead of making one machine more powerful.', 'Opening more checkout lanes instead than upgrading a single lane''s speed.', 'When load grows from 100 to 1000 requests/sec, you add 10x more inference servers instead of upgrading one.', '[{"text":"Making one machine more powerful.","id":"verticalscaling"}]'::jsonb, 'Horizontal scaling works well for stateless services (inference). You just add replicas and load-balance. It doesn''t work for databases (replication is complex). Horizontal scaling has overhead — load balancing, coordination — so it''s not free, but it''s more cost-effective at scale than vertical scaling.', 'Horizontal scaling is how cloud services grow without hitting hard limits.', 'Design services to be stateless so horizontal scaling is simple.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('verticalscaling', 'Vertical scaling', '', '', ARRAY['vertical scaling','scale up','bigger machine']::text[], 'Core', 'Making a single machine more powerful (more CPU, more GPU, more memory) instead of adding more machines.', 'Buying a bigger truck instead of buying more trucks.', 'Instead of 5 GPU servers, buy 1 with 5 GPUs (or 1 huge GPU).', '[{"text":"Adding more machines.","id":"horizontalscaling"}]'::jsonb, 'Vertical scaling hits limits — you can''t make a machine infinitely powerful. It''s also wasteful if you don''t use the full capacity. But for certain workloads (like very large model training), you have no choice. Vertical scaling is usually simpler operationally (fewer machines to manage) but more expensive per unit of capacity.', 'Vertical scaling works for bursty, high-powered jobs; horizontal is better for continuous services.', 'Prefer horizontal scaling; use vertical only when you hit architectural limits.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('modelrouting', 'Model routing', '', '', ARRAY['model routing','model selection']::text[], 'Rising', 'Intelligently choosing which model to run for each request based on latency, cost, or accuracy needs.', 'A dispatcher choosing between a fast courier and a slow truck depending on urgency and package size.', 'Simple questions go to a fast, cheap 7B model; complex ones go to a slower, smarter 70B model.', '[]'::jsonb, 'Model routing lets you optimize cost and quality per request instead of one-size-fits-all. You need a router (ML model, rule engine, or heuristic) that decides which model to use. Challenges: building the router, handling failures, and explaining choices to users.', 'Model routing can cut costs by serving simple requests cheaply.', 'Build a router; instrument request metadata so the router has signal; monitor outcomes.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('fallbackmodel', 'Fallback model', '', '', ARRAY['fallback model','backup model','fallback']::text[], 'Rising', 'A secondary model you route to if the primary fails or gets overloaded.', 'Calling your backup driver if the main driver is sick.', 'Primary model is Claude; it''s overloaded; requests fall through to GPT-4 as a fallback.', '[]'::jsonb, 'Fallback models add resilience but cost money (you pay for both). You need to decide when to fallback — timeout, error rate spike, or queue depth. Fallbacks should be clearly logged so you know when they''re happening.', 'Fallbacks are insurance against outages at the cost of higher per-request spend.', 'Implement fallback logic with timeouts and error rates; monitor fallback rate closely.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('cascade', 'Cascade', '', '', ARRAY['cascade','cascading','chain']::text[], 'Rising', 'A chain of fallbacks — try model A, if it fails try B, if that fails try C.', 'Calling your boss, then their boss, then the CEO if each person is unavailable.', 'Route to vLLM (fast), fall back to TensorRT (slower), fall back to ONNX Runtime (slowest).', '[]'::jsonb, 'Cascading adds redundancy and flexibility. You get graceful degradation — the system is still responsive even if preferred options fail. The tradeoff: increased complexity, higher costs (you pay for unused backups), and potential cascading failures if not designed carefully.', 'Cascades provide safety but are expensive — use when reliability matters more than cost.', 'Implement cascades with clear failure policies; avoid cascades that degrade UX (slow fallback = bad UX).', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('costoptimization', 'Cost optimization', '', '', ARRAY['cost optimization','cost savings','reduce costs']::text[], 'Core', 'Systematically reducing inference costs through quantization, caching, routing, and careful hardware choices.', 'Tightening your budget without cutting corners on quality.', 'Quantizing models saves 3x on memory, caching saves 50% on redundant queries, using cheaper models saves more.', '[]'::jsonb, 'Cost levers: model size (smaller = cheaper), quantization, caching, batching, regional pricing, and reserved capacity. You optimize by profiling where money goes (what % is model inference vs infrastructure?) and attacking the largest item first.', 'Every 10% reduction in inference cost is margin — even 1% matters at scale.', 'Measure cost per token and per request; profile regularly; quantize early.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('spotinstances', 'Spot instances', '', '', ARRAY['spot instances','spot','spot vms']::text[], 'Rising', 'Cheap cloud compute that can be interrupted at any time — you save money in exchange for the risk of losing the instance.', 'Buying concert tickets at the last minute for 90% off, but the show might be cancelled.', 'A spot GPU costs 80% less than an on-demand GPU, but cloud providers can reclaim it with 30 seconds notice.', '[]'::jsonb, 'Spot instances are good for fault-tolerant workloads. If one instance dies, you spin up another. Inference services can handle spot instances: if a server dies, requests fail over to another replica. Training is risky on spot (you might lose 8 hours of progress). Spot pricing varies by region and demand.', 'Spot instances can cut compute costs dramatically if your workload is fault-tolerant.', 'Use spot for inference (stateless), not training; build recovery into your orchestration.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('ondemand', 'On-demand', '', '', ARRAY['on-demand','on demand','pay as you go']::text[], 'Core', 'Paying for compute as you use it without long-term commitment — expensive but flexible.', 'Renting a car for one day instead of buying it.', 'Spin up an inference server for an hour, use it, shut it down; pay only for that hour.', '[]'::jsonb, 'On-demand is the default in cloud computing. You pay more per unit than reserved capacity, but you avoid the risk of overcommitting. For bursty workloads (spiky traffic), on-demand is better. For steady workloads, reserved capacity saves money.', 'On-demand is flexible but expensive; switch to reserved capacity if usage is predictable.', 'On-demand is great for dev/test; production workloads should use reserved or spot.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('reservedcapacity', 'Reserved capacity', '', '', ARRAY['reserved capacity','reserved instance','commitment']::text[], 'Core', 'Buying compute in advance (1-3 years) at a discount — saves money if you can predict usage.', 'Buying a season pass to the gym instead of paying per visit.', 'You know you''ll need 100 GPUs for 2 years; commit upfront and save 40% vs on-demand.', '[]'::jsonb, 'Reserved instances require guessing usage correctly. Overcommit and you waste money. Undercommit and you miss the discount. They''re also hard to change once purchased. Good for steady, predictable workloads; bad for growing startups or experimental projects.', 'Reserved capacity is profitable for mature, predictable products.', 'Use reserved instances for baseline load; burst with on-demand or spot.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('inferencecost', 'Inference cost', '', '', ARRAY['inference cost','inference expense','serving cost']::text[], 'Core', 'The cost of running predictions — usually per token or per request.', 'The cost of electricity to run your ChatBot, not the cost to train it.', 'At $0.01 per 1K tokens, a 1M-token inference job costs $10.', '[]'::jsonb, 'Inference cost = (model weights × cost per token) + (infrastructure overhead). Inference is cheaper than training but happens constantly. As usage grows, inference cost dominates. Optimizations here have huge leverage.', 'Inference cost determines unit economics — it''s the main variable cost per customer.', 'Optimize inference cost first; it scales linearly with usage.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('trainingcost', 'Training cost', '', '', ARRAY['training cost','training expense','training budget']::text[], 'Core', 'The upfront cost to train a model — includes compute, data, and development time.', 'The cost to build a factory, vs the cost to run it.', 'Training a 7B model on 1T tokens costs ~$100K in compute; inference on that model costs pennies per user.', '[]'::jsonb, 'Training cost is a one-time or periodic expense. Once a model is trained, you can serve it infinitely. Training is bursty (you use compute for weeks, then nothing for months). Infrastructure choices here are different than inference.', 'Training cost is investment; inference cost is recurring expense.', 'Invest in training efficiency; distributed training, better hardware, and optimized algorithms all matter.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('totalcostofownership', 'Total cost of ownership', '', '', ARRAY['total cost of ownership','tco','lifetime cost']::text[], 'Core', 'The full cost of running a system over its lifetime — training + inference + operations + maintenance.', 'The cost of owning a car: upfront purchase, fuel, insurance, maintenance, depreciation.', 'A model costs $100K to train, $10K/month to serve, and has a 2-year useful life. TCO = $100K + $240K = $340K.', '[]'::jsonb, 'TCO includes hidden costs: engineering time to maintain, retraining when the model becomes stale, handling support issues, compliance. A cheap model might have expensive operations (buggy serving code, poor monitoring).', 'TCO is how you compare different solutions — a cheap model with expensive operations might cost more than a pricey model that''s reliable.', 'Instrument everything so TCO is visible; cheap training but expensive ops is a bad deal.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('edgedeployment', 'Edge deployment', '', '', ARRAY['edge deployment','edge computing','on-device']::text[], 'Rising', 'Running the model on user devices or regional servers instead of a central data center — faster but limited by device compute.', 'Running a factory branch in each city instead of shipping everything from one central factory.', 'Running a small LLM on a user''s phone using llama.cpp instead of sending requests to a cloud API.', '[]'::jsonb, 'Edge deployment has latency and privacy benefits (no network round-trip, data stays local) but size and accuracy constraints (device has limited memory and compute). Good for on-device AI; bad for large models. Requires careful model optimization (quantization, pruning).', 'Edge deployment improves privacy and latency, but limits model size and inference quality.', 'For edge, prioritize model size and speed; 7B quantized runs on phones, 70B doesn''t.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[])
